/**
 * Panel Bootstrap - Inline Version (Minified)
 *
 * This file is for REFERENCE ONLY and documentation.
 * The actual bootstrap code should be INLINED in each panel's .hbs file.
 *
 * Why inline instead of external script?
 * ========================================
 * When a panel is embedded in an iframe, the browser cannot load this file
 * from /js/panel-bootstrap-inline.min.js because it needs the prefix
 * /neon/api/demo-integration/js/panel-bootstrap-inline.min.js
 *
 * But we need the bootstrap to SET that prefix in the first place!
 * This is a "chicken and egg" problem.
 *
 * Solution: Inline the bootstrap script directly in the HTML <head>,
 * so it loads synchronously with the HTML and has no external dependencies.
 *
 * Size: ~574 bytes minified (negligible impact on HTML size)
 *
 * Usage in .hbs files:
 * ====================
 *
 * <head>
 *     <meta charset="UTF-8">
 *     <meta name="viewport" content="width=device-width, initial-scale=1.0">
 *     <title>Your Panel</title>
 *
 *     <!-- Panel Bootstrap (inline to avoid path resolution issues) -->
 *     <script>
 * (function(w){'use strict';function e(){try{return w.self!==w.top}catch(e){return true}}const m=e(),p=m?'/neon/api/demo-integration':'';w.__PANEL_EMBED_PREFIX__=p;w.__PANEL_IS_EMBEDDED__=m;w.__fixScriptSrc__=function(s){if(!s||!m||s.startsWith('http')||s.startsWith('//')||!s.startsWith('/')||s.startsWith(p))return s;return p+s}})(window);
 *     </script>
 *
 *     <script src="/js/panel-api-helper.js"></script>
 *     <!-- rest of scripts -->
 * </head>
 *
 *
 * Readable Version (for understanding):
 * ======================================
 */

(function(window) {
    'use strict';

    // Detect if embedded in iframe
    function isEmbedded() {
        try {
            return window.self !== window.top;
        } catch (e) {
            // Cross-origin restriction means we're definitely embedded
            return true;
        }
    }

    // Calculate prefix
    const embedded = isEmbedded();
    const prefix = embedded ? '/neon/api/demo-integration' : '';

    // Set global variables for panel-api-helper.js to use
    window.__PANEL_EMBED_PREFIX__ = prefix;
    window.__PANEL_IS_EMBEDDED__ = embedded;

    // Helper function to fix script src (used by fixStaticResources)
    window.__fixScriptSrc__ = function(src) {
        if (!src || !embedded) return src;
        if (src.startsWith('http') || src.startsWith('//')) return src;
        if (!src.startsWith('/')) return src;
        if (src.startsWith(prefix)) return src; // Already fixed
        return prefix + src;
    };
})(window);

/**
 * Minified Version (574 bytes):
 * ==============================
 *
 * Copy this line and paste it in your panel's <head> inside a <script> tag:
 */

